async function onResponse(context, request, response) {
  const GITHUB_USER = 'minhdat783z-cell';
  const REPO_NAME = 'Baokhanhcheat';
  const BRANCH = 'main';
  const baseRaw = `https://raw.githubusercontent.com/${GITHUB_USER}/${REPO_NAME}/${BRANCH}/`;

  function htb(hex) {
    let bytes = "";
    for (let i = 0; i < hex.length; i += 2) {
      bytes += String.fromCharCode(parseInt(hex.substr(i, 2), 16));
    }
    return bytes;
  }

  const url = request.url;

  try {
    let hexSource = "";
    if (url.includes("/GetBackpack")) {
      hexSource = "config_folder/lov2.txt";
    } else if (url.includes("/fileinfo")) {
      hexSource = "assets_folder/3dr.txt";
    } else if (url.includes("/assetindexer")) {
      hexSource = "bypass_logic/indr.txt";
    }

    if (hexSource !== "") {
      const finalUrl = baseRaw + hexSource;
      const resFetch = await fetch(finalUrl);
      if (!resFetch.ok) return response;

      const rawData = await resFetch.text();
      response.body = htb(rawData.trim().replace(/\s/g, ''));
      response.statusCode = 200;
      response.headers["Content-Type"] = "application/octet-stream";
      delete response.headers["Content-Length"];
      return response;
    }
  } catch (e) {
    return response;
  }
  return response;
}
